<?php
namespace App\Controllers; use App\Core\{Controller,Database,View}; use function App\Core\{flash,redirect,verify_csrf}; final class TemplateController extends Controller{public function index():string{$this->requireAuth();return View::render('templates/index',['templates'=>Database::pdo()->query('SELECT * FROM post_templates ORDER BY id DESC')->fetchAll()]);} public function store():string{$this->requireAuth();verify_csrf();$now=date('Y-m-d H:i:s');Database::pdo()->prepare('INSERT INTO post_templates (name,body,is_default,created_at,updated_at) VALUES (?,?,0,?,?)')->execute([trim($_POST['name']??''),(string)($_POST['body']??''),$now,$now]);flash('success','テンプレートを保存しました。');redirect('/templates');} public function delete():string{$this->requireAuth();verify_csrf();Database::pdo()->prepare('DELETE FROM post_templates WHERE id=? AND is_default=0')->execute([(int)$_POST['id']]);redirect('/templates');}}
